SELECT COUNT(DISTINCT S.pk_siape) AS quantidade_servidores  FROM servidor S  JOIN cargo C ON S.pk_siape = C.fk_siape  WHERE S.saiu_do_ifg = FALSE  AND S.sigla_campus = 'ITU'  AND LOWER(S.area_ingresso) LIKE LOWER('%educacao%')  AND C.data_entrada <= '2023-06-30'  AND (C.data_saida IS NULL OR C.data_saida > '2023-06-30')  GROUP BY S.sigla_campus  HAVING COUNT(DISTINCT S.pk_siape) > 0  ORDER BY quantidade_servidores DESC  LIMIT 1